#include "kernel_operator.h"

class KernelConvTranspose3dMultiplyMaxGlobalAvgPoolClampCustom {
public:
    __aicore__ inline KernelConvTranspose3dMultiplyMaxGlobalAvgPoolClampCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR w, GM_ADDR b, GM_ADDR y,
                                uint32_t N, uint32_t Cin, uint32_t Din, uint32_t Hin, uint32_t Win,
                                uint32_t Cout, uint32_t Kd, uint32_t Kh, uint32_t Kw,
                                uint32_t hasBias)
    {
        xPtr_ = reinterpret_cast<__gm__ float*>(x);
        wPtr_ = reinterpret_cast<__gm__ float*>(w);
        bPtr_ = reinterpret_cast<__gm__ float*>(b);
        yPtr_ = reinterpret_cast<__gm__ float*>(y);
        N_ = N; Cin_ = Cin; Din_ = Din; Hin_ = Hin; Win_ = Win;
        Cout_ = Cout; Kd_ = Kd; Kh_ = Kh; Kw_ = Kw;
        HasBias_ = hasBias;
        Dout_ = Din_ + Kd_ - 1u;
        Hout_ = Hin_ + Kh_ - 1u;
        Wout_ = Win_ + Kw_ - 1u;
        volOut_ = Dout_ * Hout_ * Wout_;
    }

    __aicore__ inline void Process()
    {
        // Single-core computation by design (blockDim=1)
        if (N_ == 0 || Cin_ == 0 || Cout_ == 0) {
            return;
        }
        // Pass 1: compute global max over y and accumulate per-(n,co) sum of y.
        float globalMax = -AscendC::INFINITY_F;
        // Initialize sums in output buffer to zero (size N*Cout)
        const uint32_t sumCount = N_ * Cout_;
        for (uint32_t idx = 0; idx < sumCount; ++idx) {
            yPtr_[idx] = 0.0f;
        }

        for (uint32_t n = 0; n < N_; ++n) {
            for (uint32_t co = 0; co < Cout_; ++co) {
                float sumY = 0.0f;
                for (uint32_t od = 0; od < Dout_; ++od) {
                    for (uint32_t oh = 0; oh < Hout_; ++oh) {
                        for (uint32_t ow = 0; ow < Wout_; ++ow) {
                            float val = 0.0f;
                            // Sum over input channels and kernel
                            for (uint32_t ci = 0; ci < Cin_; ++ci) {
                                for (uint32_t kd = 0; kd < Kd_; ++kd) {
                                    int32_t id = static_cast<int32_t>(od) - static_cast<int32_t>(kd);
                                    if (id < 0 || id >= static_cast<int32_t>(Din_)) continue;
                                    for (uint32_t kh = 0; kh < Kh_; ++kh) {
                                        int32_t ih = static_cast<int32_t>(oh) - static_cast<int32_t>(kh);
                                        if (ih < 0 || ih >= static_cast<int32_t>(Hin_)) continue;
                                        for (uint32_t kw = 0; kw < Kw_; ++kw) {
                                            int32_t iw = static_cast<int32_t>(ow) - static_cast<int32_t>(kw);
                                            if (iw < 0 || iw >= static_cast<int32_t>(Win_)) continue;

                                            uint64_t xOff = ((((uint64_t)n * Cin_ + ci) * Din_ + static_cast<uint32_t>(id)) * Hin_ + static_cast<uint32_t>(ih)) * Win_ + static_cast<uint32_t>(iw);
                                            uint64_t wOff = ((((uint64_t)ci * Cout_ + co) * Kd_ + kd) * Kh_ + kh) * Kw_ + kw;
                                            float xVal = xPtr_[xOff];
                                            float wVal = wPtr_[wOff];
                                            val += xVal * wVal;
                                        }
                                    }
                                }
                            }
                            if (HasBias_) {
                                val += bPtr_[co];
                            }
                            // Update global max and per-(n,co) sum
                            if (val > globalMax) {
                                globalMax = val;
                            }
                            sumY += val;
                        }
                    }
                }
                // Store the sumY temporarily into y buffer at [n*Cout + co]
                yPtr_[n * Cout_ + co] = sumY;
            }
        }

        // Pass 2: compute avg per (n,co), scale by global max, and clamp to [0,1]
        const float denom = static_cast<float>(volOut_);
        for (uint32_t n = 0; n < N_; ++n) {
            for (uint32_t co = 0; co < Cout_; ++co) {
                uint64_t idx = (uint64_t)n * Cout_ + co;
                float sumY = yPtr_[idx];
                float avgY = sumY / denom;
                float outVal = avgY * globalMax;
                // clamp [0.0, 1.0]
                if (outVal < 0.0f) outVal = 0.0f;
                if (outVal > 1.0f) outVal = 1.0f;
                yPtr_[idx] = outVal;
            }
        }
    }

private:
    __gm__ float* xPtr_{nullptr};
    __gm__ float* wPtr_{nullptr};
    __gm__ float* bPtr_{nullptr};
    __gm__ float* yPtr_{nullptr};

    uint32_t N_{0}, Cin_{0}, Din_{0}, Hin_{0}, Win_{0};
    uint32_t Cout_{0}, Kd_{0}, Kh_{0}, Kw_{0};
    uint32_t Dout_{0}, Hout_{0}, Wout_{0};
    uint32_t volOut_{0};
    uint32_t HasBias_{0};
};

